+
+        fn mask_case(input: &str, upper_mask: &[bool]) -> String {
+            input
+                .chars()
+                .zip(upper_mask.iter().copied())
+                .map(
+                    |(ch, upper)| {
+                        if upper { ch.to_ascii_uppercase() } else { ch }
+                    },
+                )
+                .collect()
+        }
+
+        fn make_inclusion_entry(id: String, category: ExtensionCategory) -> InclusionEntry {
