+                    ExtensionCategory::Command,
+                    ExtensionCategory::Provider,
+                    ExtensionCategory::EventHook,
+                    ExtensionCategory::UiComponent,
+                    ExtensionCategory::Configuration,
+                    ExtensionCategory::Multi,
+                    ExtensionCategory::General,
