+            fn build_test_plan_coverage_invariants(task_id in "[a-z0-9_-]{1,32}") {
+                let inclusion = InclusionList {
+                    schema: "pi.ext.inclusion.v1".to_string(),
+                    generated_at: "2026-01-01T00:00:00Z".to_string(),
+                    task: Some(task_id.clone()),
